interface ActionButton extends Omit<CoreActionButton, 'onClick'> {
  onClick: (event: React.MouseEvent<HTMLButtonElement>) => void;
}

type AlignmentType = 'left' | 'center' | 'right';

export interface BaseColumn<Item> {
  title: string;
  accessorKey: keyof Item;
  width?: string;
  enableSorting?: boolean;
  headerAlign?: AlignmentType;
}

export interface TextColumn<Item> extends BaseColumn<Item> {
  type: 'text';
  render?: (item: Item, value: unknown) => React.ReactNode;
}

export interface DateColumn<Item> extends BaseColumn<Item> {
  type: 'date';
  format?: 'short' | 'medium' | 'long' | 'relative';
  render?: (item: Item, value: Date | string | number) => React.ReactNode;
}

export interface SwitchColumn<Item> extends BaseColumn<Item> {
  type: 'switch';
  onToggle?: (checked: boolean, item: Item) => void;
}

export interface ButtonColumn<Item> extends BaseColumn<Item> {
  type: 'button';
  buttonText: string;
  variant?: 'primary' | 'destructive' | 'outline' | 'ghost' | 'link';
  onClick: (item: Item) => void;
}

export interface CopyColumnLabels {
  copyTooltip?: string;
  copiedTooltip?: string;
}

export interface CopyColumn<Item> extends BaseColumn<Item> {
  type: 'copy';
}

export interface BadgeColumn<Item> extends BaseColumn<Item> {
  type: 'badge';
  variant?: 'default' | 'secondary' | 'destructive' | 'outline' | 'success';
}

export interface ActionsColumn<Item> extends Omit<BaseColumn<Item>, 'accessorKey'> {
  type: 'actions';
  accessorKey?: keyof Item;
  render: (item: Item) => React.ReactNode;
}

export interface CustomColumn<Item> extends BaseColumn<Item> {
  type: 'custom';
  render: (item: Item, value: unknown) => React.ReactNode;
}

export type Column<Item> =
  | TextColumn<Item>
  | DateColumn<Item>
  | SwitchColumn<Item>
  | ButtonColumn<Item>
  | CopyColumn<Item>
  | BadgeColumn<Item>
  | ActionsColumn<Item>
  | CustomColumn<Item>;

export interface EmptyStateProps {
  title: string;
  subtitle?: string;
  action?: ActionButton;
}

export interface DataTableProps<Item> {
  data: Item[];
  columns: Column<Item>[];
  loading?: boolean;
  loader?: React.ReactNode;
  emptyState?: EmptyStateProps;
  onRowClick?: (rowData: Item) => void;
  className?: string;
  headerAlign?: AlignmentType;
}

const ALIGNMENT_CLASSES = {
  text: {
    left: 'text-left',
    center: 'text-center',
    right: 'text-right',
  },
  flex: {
    left: 'justify-start',
    center: 'justify-center',
    right: 'justify-end',
  },
} as const;

const isEmpty = (value: unknown): boolean => {
  return value === null || value === undefined || value === '';
};

const formatDate = (value: Date | string | number, format: string = 'medium'): string => {
  const date = new Date(value);
  if (isNaN(date.getTime())) return 'Invalid Date';

  switch (format) {
    case 'short':
      return date.toLocaleDateString();
    case 'long':
      return date.toLocaleDateString(undefined, {
        weekday: 'long',
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      });
    case 'relative': {
      const now = new Date();
      const diffTime = date.getTime() - now.getTime();
      const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      if (Math.abs(diffDays) === 0) return 'Today';
      if (diffDays === 1) return 'Tomorrow';
      if (diffDays === -1) return 'Yesterday';
      if (diffDays > 0) return `In ${diffDays} days`;
      return `${Math.abs(diffDays)} days ago`;
    }
    case 'medium':
    default:
      return date.toLocaleDateString(undefined, {
        year: 'numeric',
        month: 'short',
        day: 'numeric',
      });
  }
};

const DEFAULT_COPY_LABELS: Required<CopyColumnLabels> = {
  copyTooltip: 'Copy to clipboard',
  copiedTooltip: 'Copied!',
};

/**
 * Copy button with clipboard functionality.
 * @param props - Component props.
 * @param props.value - Value to copy
 * @param props.labels - Tooltip labels
 * @returns JSX element
 */
function CopyButton({
  value,
  labels = DEFAULT_COPY_LABELS,
}: {
  value: unknown;
  labels?: CopyColumnLabels;
}) {
  const [copied, setCopied] = useState(false);
  const [copyTooltipOpen, setCopyTooltipOpen] = useState(false);
  const stringValue = String(value);

  const handleCopy = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (!value) return;

    try {
      await navigator.clipboard.writeText(stringValue);
      setCopied(true);
      setCopyTooltipOpen(true);

      setTimeout(() => {
        setCopied(false);
        setCopyTooltipOpen(false);
      }, 2000);
    } catch (error) {
      console.error('Failed to copy text:', error);
    }
  };

  return (
    <InlineCode className="w-full flex items-center justify-between gap-2 pr-1">
      <span className="min-w-0 flex-1">
        <MiddleEllipsisText text={stringValue} className="text-muted-foreground" />
      </span>
      <Tooltip open={copyTooltipOpen} onOpenChange={setCopyTooltipOpen}>
        <TooltipTrigger asChild>
          <Button
            variant="ghost"
            size="sm"
            onClick={handleCopy}
            className="h-6 w-6 p-0 hover:bg-muted/50 shrink-0"
            aria-label={copied ? labels.copiedTooltip : labels.copyTooltip}
          >
            <Copy className="h-3 w-3" />
          </Button>
        </TooltipTrigger>
        <TooltipContent>
          <p>{copied ? labels.copiedTooltip : labels.copyTooltip}</p>
        </TooltipContent>
      </Tooltip>
    </InlineCode>
  );
}

/**
 * Renders a text column cell.
 * @param item - Data item.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderTextColumn<Item>(
  item: Item,
  value: unknown,
  column: TextColumn<Item>,
): React.ReactNode {
  if (column.render) {
    return column.render(item, value);
  }

  return <span className="text-muted-foreground">{String(value)}</span>;
}

/**
 * Renders a date column cell.
 * @param item - Data item.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderDateColumn<Item>(
  item: Item,
  value: Date | string | number,
  column: DateColumn<Item>,
): React.ReactNode {
  if (column.render) {
    return column.render(item, value);
  }
  const formattedDate = formatDate(value, column.format);

  return (
    <span className="text-muted-foreground" title={new Date(value).toISOString()}>
      {formattedDate}
    </span>
  );
}

/**
 * Renders a switch column cell.
 * @param item - Data item.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderSwitchColumn<Item>(
  item: Item,
  value: boolean,
  column: SwitchColumn<Item>,
): React.ReactNode {
  const handleToggle = (checked: boolean) => {
    column.onToggle?.(checked, item);
  };

  return (
    <div onClick={(e) => e.stopPropagation()}>
      <Switch checked={!!value} onCheckedChange={handleToggle} />
    </div>
  );
}

/**
 * Renders a button column cell.
 * @param item - Data item.
 * @param column - Column configuration.
 * @returns React node
 */
function renderButtonColumn<Item>(item: Item, column: ButtonColumn<Item>): React.ReactNode {
  const handleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    column.onClick(item);
  };

  return (
    <Button variant={column.variant} size="sm" onClick={handleClick}>
      {column.buttonText}
    </Button>
  );
}

/**
 * Renders a badge column cell.
 * @param value - Cell value.
 * @param column - Column configuration.
 * @returns React node
 */
function renderBadgeColumn<Item>(value: unknown, column: BadgeColumn<Item>): React.ReactNode {
  return <Badge variant={column.variant}>{String(value)}</Badge>;
}

/**
 * Renders a copy column cell.
 * @param value - Cell value.
 * @returns React node
 */
function renderCopyColumn(value: unknown): React.ReactNode {
  return <CopyButton value={value} />;
}

/**
 * Empty state component for data table.
 * @param props - Component props.
 * @param props.title - Empty state title.
 * @param props.subtitle - Empty state subtitle.
 * @param props.action - Optional action button config.
 * @returns JSX element
 */
function EmptyState({ title, subtitle, action }: EmptyStateProps) {
  return (
    <div className="text-center py-12">
      <h3 className="text-md font-medium text-foreground mb-2">{title}</h3>
      {subtitle && <p className="text-sm text-muted-foreground mb-4">{subtitle}</p>}
      {action && (
        <Button variant={action.variant} onClick={action.onClick}>
          {action.label}
        </Button>
      )}
    </div>
  );
}

/**
 * Generic data table component.
 * @param props - Component props.
 * @param props.data - Table data items.
 * @param props.columns - Column configurations.
 * @param props.loading - Loading state.
 * @param props.loader - Custom loader component.
 * @param props.emptyState - Empty state configuration.
 * @param props.onRowClick - Row click handler.
 * @param props.className - Additional CSS classes.
 * @param props.headerAlign - Default header alignment.
 * @returns JSX element
 */
export function DataTable<Item>({
  data,
  columns,
  loading = false,
  loader,
  emptyState,
  onRowClick,
  className,
  headerAlign = 'left',
}: DataTableProps<Item>) {
  const [sorting, setSorting] = useState<SortingState>([]);

  const tableColumns = useMemo<ColumnDef<Item>[]>(() => {
    return columns.map((column, index) => {
      return {
        id: `column-${index}`,
        accessorKey: column.accessorKey as string,
        header: column.title,
        size: column.width
          ? isNaN(Number(column.width))
            ? undefined
            : Number(column.width)
          : undefined,
        enableSorting: column.enableSorting !== false && !!column.accessorKey,
        meta: {
          headerAlign: column.headerAlign || headerAlign || 'left',
          column: column,
        },

        cell: ({ getValue, row }) => {
          const value = getValue();
          const item = row.original;

          if (column.type === 'actions') {
            return <div onClick={(e) => e.stopPropagation()}>{column.render(item)}</div>;
          }

          if (column.type === 'custom') {
            return <>{column.render(item, value)}</>;
          }

          if (column.type === 'switch') {
            return renderSwitchColumn(item, value as boolean, column);
          }

          if (column.type === 'button') {
            return renderButtonColumn(item, column);
          }

          if (isEmpty(value)) {
            return null;
          }

          switch (column.type) {
            case 'text':
              return renderTextColumn(item, value, column);
            case 'date':
              return renderDateColumn(item, value as Date | string | number, column);
            case 'copy':
              return renderCopyColumn(value);
            case 'badge':
              return renderBadgeColumn(value, column);
            default:
              return <span className="text-foreground">{String(value)}</span>;
          }
        },
      };
    });
  }, [columns, headerAlign]);

  const table = useReactTable({
    data,
    columns: tableColumns,
    state: {
      sorting,
    },
    onSortingChange: setSorting,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    manualPagination: true,
  });

  if (loading) {
    return (
      <div className={cn('w-full flex items-center justify-center py-8', className)}>
        {loader || <Spinner />}
      </div>
    );
  }

  return (
    <div className={cn('w-full', className)}>
      <Table>
        <TableHeader>
          {table.getHeaderGroups().map((headerGroup) => (
            <TableRow key={headerGroup.id}>
              {headerGroup.headers.map((header) => {
                const canSort = header.column.getCanSort();
                const sortDirection = header.column.getIsSorted();
                const meta = header.column.columnDef.meta as {
                  headerAlign: AlignmentType;
                  column: Column<Item>;
                };

                return (
                  <TableHead
                    key={header.id}
                    className={cn(
                      canSort && 'hover:bg-muted/50',
                      'transition-colors',
                      ALIGNMENT_CLASSES.text[meta.headerAlign],
                    )}
                    style={{
                      width: meta.column.width,
                      minWidth: meta.column.width,
                      maxWidth: meta.column.width,
                    }}
                    onClick={canSort ? header.column.getToggleSortingHandler() : undefined}
                    isSortable={canSort}
                    sortDirection={sortDirection}
                  >
                    {flexRender(header.column.columnDef.header, header.getContext())}
                  </TableHead>
                );
              })}
            </TableRow>
          ))}
        </TableHeader>
        <TableBody>
          {table.getRowModel().rows.length === 0 ? (
            <TableRow disableHover>
              <TableCell colSpan={columns.length}>
                <EmptyState
                  {...(emptyState ?? {
                    title: 'No data available',
                    subtitle: 'There are no items to display.',
                  })}
                />
              </TableCell>
            </TableRow>
          ) : (
            table.getRowModel().rows.map((row) => (
              <TableRow
                key={row.id}
                className={cn(
                  onRowClick && 'cursor-pointer hover:bg-muted/50',
                  'transition-colors',
                )}
                onClick={() => onRowClick?.(row.original)}
              >
                {row.getVisibleCells().map((cell) => {
                  const meta = cell.column.columnDef.meta as {
                    column: Column<Item>;
                  };
                  return (
                    <TableCell
                      key={cell.id}
                      className="text-left"
                      style={{
                        width: meta.column.width,
                        minWidth: meta.column.width,
                        maxWidth: meta.column.width,
                      }}
                    >
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </TableCell>
                  );
                })}
              </TableRow>
            ))
          )}
        </TableBody>
      </Table>
    </div>
  );
}

/**
 * Form action buttons component.
 * @module form-actions
 * @internal
 */

import type { ActionButton } from '@auth0/universal-components-core';
import * as React from 'react';

import { Button } from '@/components/ui/button';
import { Spinner } from '@/components/ui/spinner';
import { cn } from '@/lib/utils';

export interface FormActionsProps<T = void> {
  hasUnsavedChanges?: boolean;
  isLoading?: boolean;
  nextAction?: Partial<ActionButton<T>>;
  previousAction?: Partial<ActionButton<T>>;
  showPrevious?: boolean;
  showNext?: boolean;
  showUnsavedChanges?: boolean;
  align?: 'left' | 'right';
  className?: string;
  unsavedChangesText?: string;
}

const DEFAULT_NEXT_ACTION: ActionButton = {
  type: 'submit',
  label: 'Save',
  variant: 'primary',
  onClick: () => {},
};

const DEFAULT_PREVIOUS_ACTION: ActionButton = {
  label: 'Cancel',
  variant: 'outline',
  onClick: () => {},
};

export const FormActions: React.FC<FormActionsProps> = ({
  hasUnsavedChanges = false,
  isLoading = false,
  nextAction,
  previousAction,
  className,
  showPrevious = true,
  showNext = true,
  showUnsavedChanges = true,
  align = 'right',
  unsavedChangesText = 'Unsaved changes',
}) => {
  const nextButtonProps = React.useMemo(
    () => ({ ...DEFAULT_NEXT_ACTION, ...nextAction }),
    [nextAction],
  );

  const previousButtonProps = React.useMemo(
    () => ({ ...DEFAULT_PREVIOUS_ACTION, ...previousAction }),
    [previousAction],
  );

  const handleNextClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      nextButtonProps.onClick(e.nativeEvent);
    },
    [nextButtonProps.onClick],
  );

  const handlePreviousClick = React.useCallback(
    (e: React.MouseEvent<HTMLButtonElement>) => {
      previousButtonProps.onClick(e.nativeEvent);
    },
    [previousButtonProps.onClick],
  );

  const showUnsavedIndicator = showUnsavedChanges && hasUnsavedChanges;
  const isPreviousVisible = showUnsavedChanges ? showPrevious && hasUnsavedChanges : showPrevious;

  return (
    <div
      className={cn(
        'flex flex-row items-center gap-2 p-2',
        align === 'right' ? 'justify-end' : 'justify-start',
        className,
      )}
    >
      {showUnsavedIndicator && (
        <span className="text-sm text-muted-foreground">{unsavedChangesText}</span>
      )}

      {showPrevious && (
        <Button
          type="button"
          variant={previousButtonProps.variant}
          size={previousButtonProps.size}
          onClick={handlePreviousClick}
          disabled={
            previousButtonProps.disabled || isLoading || (showUnsavedChanges && !hasUnsavedChanges)
          }
          className={cn(
            'FormActions-previous',
            showUnsavedChanges && !isPreviousVisible && 'invisible',
          )}
          aria-hidden={showUnsavedChanges && !isPreviousVisible}
          tabIndex={isPreviousVisible ? 0 : -1}
        >
          {previousButtonProps.label}
        </Button>
      )}

      {showNext && (
        <Button
          type={nextButtonProps.type}
          variant={nextButtonProps.variant}
          size={nextButtonProps.size}
          disabled={nextButtonProps.disabled || isLoading}
          className="FormActions-next min-w-17.5"
          {...(nextButtonProps.type !== 'submit' && { onClick: handleNextClick })}
        >
          {isLoading ? (
            <Spinner
              colorScheme={nextButtonProps.variant === 'destructive' ? 'primary' : 'foreground'}
              size="sm"
              aria-hidden="true"
            />
          ) : (
            <>
              {nextButtonProps.icon && (
                <span className="mr-2" aria-hidden="true">
                  {nextButtonProps.icon as React.ReactNode}
                </span>
              )}
              {nextButtonProps.label}
            </>
          )}
        </Button>
      )}
    </div>
  );
};

/**
 * GateKeeper component for guarding content during loading, MFA step-up, and 5xx error states.
 * @module gate-keeper
 * @internal
 */

import {
  type ComponentStyling,
  type MfaRequiredError,
  getComponentStyles,
  getStatusCode,
  isMfaRequiredError,
  normalizeMfaRequiredError,
} from '@auth0/universal-components-core';
import { RefreshCcw } from 'lucide-react';
import React, { useCallback, useMemo, useState } from 'react';

import { MfaWizard } from '@/components/auth0/shared/gate-keeper/mfa-step-up/mfa-wizard';
import { StyledScope } from '@/components/auth0/shared/styled-scope';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardFooter, CardTitle } from '@/components/ui/card';
import { Dialog, DialogContent } from '@/components/ui/dialog';
import { Spinner } from '@/components/ui/spinner';
import { useTheme } from '@/hooks/shared/use-theme';
import { useTranslator } from '@/hooks/shared/use-translator';
import { useGateKeeperContext } from '@/providers/gate-keeper-context';

interface GateKeeperProps {
  styling?: ComponentStyling<Record<string, string>>;
  isLoading?: boolean;
  children: React.ReactNode;
}

/**
 * Blocking error fallback with retry button.
 * Shown for 5xx errors and dismissed MFA errors.
 *
 * @param props - Component props.
 * @param props.onRetry - Retry handler.
 * @returns Error fallback element.
 * @internal
 */
function ErrorFallback({ onRetry }: { onRetry: () => void }) {
  const { t } = useTranslator('gate_keeper');

  return (
    <Card className="text-center">
      <CardContent className="flex flex-col items-center gap-2">
        <CardTitle>{t('fallback.title')}</CardTitle>
        <CardDescription>{t('fallback.description')}</CardDescription>
      </CardContent>
      <CardFooter className="justify-center">
        <Button variant="primary" size="default" onClick={onRetry}>
          <RefreshCcw className="size-4" />
          {t('fallback.retry')}
        </Button>
      </CardFooter>
    </Card>
  );
}

/**
 * MFA step-up dialog.
 *
 * @param props - Component props.
 * @param props.error - MFA error containing the token and challenge details.
 * @param props.onComplete - Callback when MFA is completed successfully; triggers a retry.
 * @param props.onClose - Callback when the dialog is dismissed without completing.
 * @returns MFA dialog element.
 * @internal
 */
function MfaDialog({
  error,
  onComplete,
  onClose,
}: {
  error: MfaRequiredError;
  onComplete: () => void;
  onClose: () => void;
}) {
  return (
    <Dialog open onOpenChange={(open) => !open && onClose()}>
      <DialogContent>
        <MfaWizard error={error} onComplete={onComplete} onCancel={onClose} />
      </DialogContent>
    </Dialog>
  );
}

/**
 * Guards children from rendering during loading/error states. MFA step-up overlays
 * children without unmounting them, preserving any in-progress form state.
 * - Loading → spinner (blocks children)
 * - MFA required error → MFA step-up dialog overlaid on children
 * - 5xx error or dismissed MFA → blocking error fallback with retry
 * - No error → children
 *
 * @param props - Component props.
 * @param props.styling - Styling configuration forwarded to the styled scope.
 * @param props.isLoading - Whether content is loading.
 * @param props.children - Child elements to render on success.
 * @returns GateKeeper element.
 */
export function GateKeeper({ styling, isLoading, children }: GateKeeperProps) {
  const { error, onRetry } = useGateKeeperContext();
  const { isDarkMode } = useTheme();
  const [isRetrying, setIsRetrying] = useState(false);
  const [dismissedMfaToken, setDismissedMfaToken] = useState<string | null>(null);

  const styles = useMemo(() => getComponentStyles(styling, isDarkMode), [styling, isDarkMode]);

  const handleRetry = useCallback(async () => {
    setIsRetrying(true);
    setDismissedMfaToken(null);
    try {
      await onRetry?.();
    } finally {
      setIsRetrying(false);
    }
  }, [onRetry]);

  const isMfaStepUp = isMfaRequiredError(error);
  const mfaError = isMfaStepUp ? normalizeMfaRequiredError(error) : null;
  const isMfaDismissed = dismissedMfaToken === mfaError?.mfa_token;
  const statusCode = getStatusCode(error);
  const isSystemError = !!error && !!statusCode && statusCode >= 500;

  if (isLoading || isRetrying) {
    return (
      <StyledScope style={styles.variables}>
        <div className="flex items-center justify-center p-8">
          <Spinner />
        </div>
      </StyledScope>
    );
  }

  if (isSystemError || (isMfaStepUp && isMfaDismissed)) {
    return (
      <StyledScope style={styles.variables}>
        <ErrorFallback onRetry={handleRetry} />
      </StyledScope>
    );
  }

  return (
    <StyledScope style={styles.variables}>
      {children}
      {mfaError && !isMfaDismissed && (
        <MfaDialog
          error={mfaError}
          onComplete={handleRetry}
          onClose={() => setDismissedMfaToken(mfaError.mfa_token)}
        />
      )}
    </StyledScope>
  );
}

/** @internal */
import {
  normalizeFactorType,
  type EnrollmentFactor,
  type MfaAuthenticator,
  type MfaRequiredError,
} from '@auth0/universal-components-core';
import { useState } from 'react';

import { Button } from '@/components/ui/button';
import { Card, CardAction, CardHeader, CardTitle } from '@/components/ui/card';
import { List, ListItem } from '@/components/ui/list';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { useMfaRequirements } from '@/hooks/shared/use-mfa-requirements';
import { useTranslator } from '@/hooks/shared/use-translator';

interface AuthenticatorsListProps {
  error: MfaRequiredError;
  onSelectFactor: (factor: EnrollmentFactor) => void;
  onSelectAuthenticator: (authenticator: MfaAuthenticator) => void;
  onCancel: () => void;
}

/**
 * @param props - Component props.
 * @param props.error - The MFA required error.
 * @param props.onSelectFactor - Called when the user picks a factor to enroll.
 * @param props.onSelectAuthenticator - Called when the user picks an authenticator to challenge.
 * @param props.onCancel - Called when the user cancels.
 * @returns Authenticator list element, spinner during load, or null.
 * @internal
 */
export function AuthenticatorsList({
  error,
  onSelectFactor,
  onSelectAuthenticator,
  onCancel,
}: AuthenticatorsListProps) {
  const { t } = useTranslator('gate_keeper');
  const [activeItemId, setActiveItemId] = useState<string | null>(null);

  const { factors, authenticators, isEnrollMode, isLoading } = useMfaRequirements(error);

  const handleSelectFactor = (factor: EnrollmentFactor) => {
    setActiveItemId(factor.type);
    onSelectFactor(factor);
  };

  const handleSelectAuthenticator = (auth: MfaAuthenticator) => {
    setActiveItemId(auth.id);
    onSelectAuthenticator(auth);
  };

  const items = isEnrollMode
    ? factors.map((factor) => ({
        key: factor.type,
        label: t(`mfa.authenticator_type.${normalizeFactorType(factor.type)}`),
        buttonLabel: t('mfa.enroll_button'),
        onSelect: () => handleSelectFactor(factor),
      }))
    : authenticators.map((auth) => ({
        key: auth.id,
        label: auth.type
          ? t(`mfa.authenticator_type.${normalizeFactorType(auth.type)}`)
          : auth.name,
        buttonLabel: t('mfa.verify_button'),
        onSelect: () => handleSelectAuthenticator(auth),
      }));

  if (isLoading) {
    return (
      <div className="flex items-center justify-center p-8">
        <Spinner />
      </div>
    );
  }

  if (!items.length) {
    return (
      <div className="space-y-6">
        <p className="text-sm text-muted-foreground">{t('mfa.no_authenticators')}</p>
        <Separator />
        <div className="flex justify-end">
          <Button variant="outline" onClick={onCancel} aria-label={t('mfa.cancel')}>
            {t('mfa.cancel')}
          </Button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <List className="flex flex-col gap-3">
        {items.map((item) => (
          <ListItem key={item.key} aria-label={item.label}>
            <Card>
              <CardHeader>
                <CardTitle className="text-base font-semibold text-left">{item.label}</CardTitle>
                <CardAction>
                  <Button
                    variant="primary"
                    onClick={item.onSelect}
                    disabled={activeItemId !== null}
                    aria-label={`${item.buttonLabel} ${item.label}`}
                  >
                    {activeItemId === item.key ? (
                      <Spinner size="sm" colorScheme="foreground" />
                    ) : (
                      item.buttonLabel
                    )}
                  </Button>
                </CardAction>
              </CardHeader>
            </Card>
          </ListItem>
        ))}
      </List>
      <Separator />
      <div className="flex justify-end">
        <Button
          variant="outline"
          onClick={onCancel}
          disabled={activeItemId !== null}
          aria-label={t('mfa.cancel')}
        >
          {t('mfa.cancel')}
        </Button>
      </div>
    </div>
  );
}

/**
 * MFA enrollment setup form.
 * @module enrollment-form
 * @internal
 */

import {
  FACTOR_TYPE_EMAIL,
  FACTOR_TYPE_OTP,
  FACTOR_TYPE_PUSH,
  FACTOR_TYPE_SMS,
  FACTOR_TYPE_VOICE,
  createEmailContactSchema,
  createSmsContactSchema,
  type EmailContactForm,
  type EnrollmentFactor,
  type EnrollmentResponse,
  type EnrollParams,
  type MfaRequiredError,
  type SmsContactForm,
} from '@auth0/universal-components-core';
import { zodResolver } from '@hookform/resolvers/zod';
import { useCallback, useEffect, useMemo, useState } from 'react';
import { useForm } from 'react-hook-form';

import { VerifyForm } from './verify-form';

import AppleLogo from '@/assets/icons/apple-logo';
import GoogleLogo from '@/assets/icons/google-logo';
import { CopyableTextField } from '@/components/auth0/shared/copyable-text-field';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Checkbox } from '@/components/ui/checkbox';
import { DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import { Label } from '@/components/ui/label';
import { QRCodeDisplayer } from '@/components/ui/qr-code';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { TextField } from '@/components/ui/text-field';
import { useMfaStepUp } from '@/hooks/shared/use-mfa-step-up';
import { useTranslator } from '@/hooks/shared/use-translator';

interface EnrollmentFormProps {
  error: MfaRequiredError;
  factor: EnrollmentFactor;
  onComplete: () => void;
  onCancel: () => void;
}

const GUARDIAN_APP_STORE_URL = 'https://apps.apple.com/us/app/auth0-guardian/id1093447833';
const GUARDIAN_PLAY_STORE_URL = 'https://play.google.com/store/apps/details?id=com.auth0.guardian';

const FACTOR_INITIAL_STEP: Record<string, EnrollStep> = {
  [FACTOR_TYPE_OTP]: 'qr',
  [FACTOR_TYPE_PUSH]: 'install',
};

type EnrollStep = 'install' | 'input' | 'qr' | 'verify' | 'recovery';
type ContactForm = EmailContactForm | SmsContactForm;

/**
 * Multi-step enrollment form for MFA step-up. Supports OTP, Push, SMS, Voice, and Email factors.
 * Recovery codes are shown on first enrollment of any factor.
 *
 * @param props - Component props.
 * @returns Enrollment form element.
 * @internal
 */
export function EnrollmentForm({ error, factor, onComplete, onCancel }: EnrollmentFormProps) {
  const { t } = useTranslator('gate_keeper');

  const mfaToken = error.mfa_token;

  const isOtp = factor.type === FACTOR_TYPE_OTP;
  const isPush = factor.type === FACTOR_TYPE_PUSH;

  const [step, setStep] = useState<EnrollStep>(FACTOR_INITIAL_STEP[factor.type] ?? 'input');
  const [enrollResponse, setEnrollResponse] = useState<EnrollmentResponse | undefined>();
  const [recoveryConfirmed, setRecoveryConfirmed] = useState(false);

  const handleVerifyComplete = useCallback(() => {
    if (enrollResponse?.recoveryCodes?.length) {
      setStep('recovery');
    } else {
      onComplete();
    }
  }, [enrollResponse, onComplete]);

  const { enroll, isLoading } = useMfaStepUp({ error, onComplete: handleVerifyComplete });

  const contactSchema = useMemo(
    () =>
      factor.type === FACTOR_TYPE_EMAIL
        ? createEmailContactSchema(t('mfa.enroll.invalid_email'))
        : createSmsContactSchema(t('mfa.enroll.invalid_phone_number')),
    [factor.type, t],
  );

  const inputForm = useForm<ContactForm>({
    resolver: zodResolver(contactSchema),
    mode: 'onChange',
  });

  // OTP only: call enroll on mount then show QR.
  useEffect(() => {
    if (!isOtp) return;

    const initialiseOtpEnrollment = async () => {
      const response = await enroll({ mfaToken, factorType: FACTOR_TYPE_OTP });
      if (response) setEnrollResponse(response);
    };

    initialiseOtpEnrollment();
  }, [enroll, isOtp, mfaToken]);

  const handleInputSubmit = async ({ contact }: ContactForm) => {
    const params: EnrollParams =
      factor.type === FACTOR_TYPE_EMAIL
        ? { mfaToken, factorType: FACTOR_TYPE_EMAIL, email: contact }
        : { mfaToken, factorType: factor.type as 'sms' | 'voice', phoneNumber: contact };

    const response = await enroll(params);

    if (response) {
      setEnrollResponse(response);
      setStep('verify');
    }
  };

  const handlePushEnroll = async () => {
    const response = await enroll({ mfaToken, factorType: FACTOR_TYPE_PUSH });
    if (!response) return;
    setEnrollResponse(response);
    setStep('qr');
  };

  if (isOtp && !enrollResponse && step === 'qr') {
    return (
      <div className="flex items-center justify-center p-8" role="status" aria-live="polite">
        <Spinner />
      </div>
    );
  }

  if (step === 'install') {
    return (
      <>
        <DialogHeader>
          <DialogTitle>{t('mfa.enroll.install_title')}</DialogTitle>
          <DialogDescription>{t('mfa.enroll.install_description')}</DialogDescription>
        </DialogHeader>
        <Separator />

        <div className="flex gap-4 my-4">
          <a
            href={GUARDIAN_APP_STORE_URL}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-1"
          >
            <Card className="flex flex-col items-center gap-2 p-4 h-full">
              <AppleLogo className="w-8 h-8" />
              <span className="text-sm text-center">{t('mfa.enroll.app_store')}</span>
            </Card>
          </a>
          <a
            href={GUARDIAN_PLAY_STORE_URL}
            target="_blank"
            rel="noopener noreferrer"
            className="flex-1"
          >
            <Card className="flex flex-col items-center gap-2 p-4 h-full">
              <GoogleLogo className="w-8 h-8" />
              <span className="text-sm text-center">{t('mfa.enroll.google_play')}</span>
            </Card>
          </a>
        </div>

        <Separator />

        <div className="flex justify-end gap-3 mt-4">
          <Button
            type="button"
            variant="outline"
            onClick={onCancel}
            disabled={isLoading}
            aria-label={t('mfa.back')}
          >
            {t('mfa.back')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={handlePushEnroll}
            disabled={isLoading}
            aria-label={t('mfa.continue')}
          >
            {isLoading && <Spinner size="sm" colorScheme="foreground" />}
            {t('mfa.continue')}
          </Button>
        </div>
      </>
    );
  }

  if (step === 'verify' && enrollResponse) {
    return (
      <VerifyForm
        error={error}
        authenticator={{ ...enrollResponse, name: inputForm.getValues('contact') }}
        onComplete={handleVerifyComplete}
        onCancel={() => setStep(isOtp ? 'qr' : 'input')}
      />
    );
  }

  if (step === 'input') {
    const inputConfig =
      factor.type === FACTOR_TYPE_SMS || factor.type === FACTOR_TYPE_VOICE
        ? {
            label: t('mfa.enroll.phone_label'),
            description: t('mfa.enroll.phone_description'),
            title: t('mfa.enroll.phone_title'),
            placeholder: '+1 555 000 0000',
            type: 'tel',
            autoComplete: 'tel',
          }
        : {
            label: t('mfa.enroll.email_label'),
            description: t('mfa.enroll.email_description'),
            title: t('mfa.enroll.email_title'),
            placeholder: 'you@example.com',
            type: 'email',
            autoComplete: 'email',
          };

    return (
      <>
        <DialogHeader>
          <DialogTitle>{inputConfig.title}</DialogTitle>
        </DialogHeader>
        <Separator />
        <Form {...inputForm}>
          <form onSubmit={inputForm.handleSubmit(handleInputSubmit)} className="space-y-6">
            <FormField
              control={inputForm.control}
              name="contact"
              render={({ field }) => (
                <FormItem>
                  <FormLabel
                    htmlFor="enroll-input"
                    className="text-left text-sm text-(length:--font-size-paragraph) font-medium"
                  >
                    {inputConfig.label}
                  </FormLabel>
                  <FormControl>
                    <TextField
                      id="enroll-input"
                      {...field}
                      type={inputConfig.type}
                      placeholder={inputConfig.placeholder}
                      autoComplete={inputConfig.autoComplete}
                    />
                  </FormControl>
                  <FormDescription className="text-sm text-(length:--font-size-paragraph) font-normal text-left">
                    {inputConfig.description}
                  </FormDescription>
                  <FormMessage
                    className="text-left text-sm text-(length:--font-size-paragraph)"
                    id="contact-error"
                    role="alert"
                  />
                </FormItem>
              )}
            />

            <Separator />

            <div className="flex justify-end gap-3">
              <Button
                type="button"
                variant="outline"
                onClick={onCancel}
                disabled={isLoading}
                aria-label={t('mfa.back')}
              >
                {t('mfa.back')}
              </Button>
              <Button
                type="submit"
                variant="primary"
                disabled={!inputForm.formState.isValid || isLoading}
                aria-label={isLoading ? t('mfa.enroll.enrolling') : t('mfa.verify_button')}
              >
                {isLoading && <Spinner size="sm" colorScheme="foreground" />}
                {isLoading ? t('mfa.enroll.enrolling') : t('mfa.verify_button')}
              </Button>
            </div>
          </form>
        </Form>
      </>
    );
  }

  if (step === 'qr' && enrollResponse?.barcodeUri) {
    const barcodeUri = enrollResponse.barcodeUri;
    const description = isPush
      ? t('mfa.enroll.push_scan_description')
      : t('mfa.enroll.scan_description');
    return (
      <>
        <DialogHeader>
          <DialogTitle>{t('mfa.title')}</DialogTitle>
        </DialogHeader>
        <Separator />
        <div className="flex justify-center my-4">
          <QRCodeDisplayer size={160} value={barcodeUri} alt={t('mfa.enroll.qr_alt')} />
        </div>

        <div className="space-y-4" aria-describedby="qr-description">
          <p
            id="qr-description"
            className="font-semibold text-base text-center text-(length:--font-size-paragraph) text-primary"
          >
            {description}
          </p>

          {!isPush && (
            <p className="font-normal text-sm text-(length:--font-size-paragraph)">
              {t('mfa.enroll.scan_helper')}
            </p>
          )}

          {enrollResponse.authenticatorType === FACTOR_TYPE_OTP && (
            <CopyableTextField value={enrollResponse.secret} />
          )}
        </div>

        <Separator className="mt-4" />

        <div className="flex justify-end gap-3 mt-4">
          <Button
            type="button"
            variant="outline"
            onClick={isPush ? () => setStep('install') : onCancel}
            disabled={isLoading}
            aria-label={t('mfa.back')}
          >
            {t('mfa.back')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={() => (isOtp ? setStep('verify') : handleVerifyComplete())}
            disabled={isLoading}
            aria-label={t('mfa.continue')}
          >
            {isLoading && <Spinner size="sm" colorScheme="foreground" />}
            {t('mfa.continue')}
          </Button>
        </div>
      </>
    );
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>{t('mfa.enroll.recovery_title')}</DialogTitle>
        <DialogDescription>{t('mfa.enroll.recovery_description')}</DialogDescription>
      </DialogHeader>
      <Separator />
      <div className="space-y-4 my-6">
        {enrollResponse?.recoveryCodes?.[0] && (
          <CopyableTextField value={enrollResponse.recoveryCodes[0]} />
        )}

        <div className="flex items-center gap-3">
          <Checkbox
            id="recovery-confirmed"
            checked={recoveryConfirmed}
            onCheckedChange={(checked) => setRecoveryConfirmed(checked === true)}
          />
          <Label htmlFor="recovery-confirmed" className="cursor-pointer">
            {t('mfa.enroll.recovery_confirmed')}
          </Label>
        </div>
      </div>

      <Separator />

      <div className="flex justify-end gap-3 mt-4">
        <Button
          type="button"
          variant="primary"
          onClick={onComplete}
          disabled={!recoveryConfirmed}
          aria-label={t('mfa.continue')}
        >
          {t('mfa.continue')}
        </Button>
      </div>
    </>
  );
}

/**
 * MFA wizard orchestrator.
 * @module mfa-wizard
 * @internal
 */
import {
  normalizeFactorType,
  type EnrollmentFactor,
  type MfaAuthenticator,
  type MfaRequiredError,
} from '@auth0/universal-components-core';
import { useState } from 'react';

import { AuthenticatorsList } from './authenticators-list';
import { EnrollmentForm } from './enrollment-form';
import { VerifyForm } from './verify-form';

import { DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Separator } from '@/components/ui/separator';
import { useTranslator } from '@/hooks/shared/use-translator';

type MfaWizardState =
  | { view: 'list' }
  | { view: 'enroll'; factor: EnrollmentFactor }
  | { view: 'challenge'; authenticator: MfaAuthenticator };

interface MfaWizardProps {
  error: MfaRequiredError;
  onComplete: () => void;
  onCancel: () => void;
}

/**
 * Orchestrates the MFA step-up flow: list → enroll or challenge → complete.
 *
 * @param props - Component props.
 * @param props.error - The MFA required error from the step-up flow.
 * @param props.onComplete - Called after successful challenge or enrollment.
 * @param props.onCancel - Called when the user cancels the flow.
 * @returns MFA wizard element.
 * @internal
 */
export function MfaWizard({ error, onComplete, onCancel }: MfaWizardProps) {
  const { t } = useTranslator('gate_keeper');
  const [state, setState] = useState<MfaWizardState>({ view: 'list' });

  const handleSelectFactor = (factor: EnrollmentFactor) =>
    setState({ view: 'enroll', factor: { ...factor, type: normalizeFactorType(factor.type) } });

  const handleSelectAuthenticator = (authenticator: MfaAuthenticator) =>
    setState({ view: 'challenge', authenticator });

  if (state.view === 'enroll') {
    return (
      <EnrollmentForm
        error={error}
        factor={state.factor}
        onComplete={onComplete}
        onCancel={() => setState({ view: 'list' })}
      />
    );
  }

  if (state.view === 'challenge') {
    return (
      <VerifyForm
        error={error}
        authenticator={state.authenticator}
        onComplete={onComplete}
        onCancel={() => setState({ view: 'list' })}
      />
    );
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>{t('mfa.title')}</DialogTitle>
        <DialogDescription>{t('mfa.subtitle')}</DialogDescription>
      </DialogHeader>
      <Separator />
      <AuthenticatorsList
        error={error}
        onSelectFactor={handleSelectFactor}
        onSelectAuthenticator={handleSelectAuthenticator}
        onCancel={onCancel}
      />
    </>
  );
}

/** @internal */

import { FACTOR_TYPE_RECOVERY_CODE } from '@auth0/universal-components-core';
import { useEffect, useRef, useState } from 'react';
import { useForm } from 'react-hook-form';

import { Button } from '@/components/ui/button';
import { Form, FormControl, FormField, FormItem, FormMessage } from '@/components/ui/form';
import { Link } from '@/components/ui/link';
import { OTPField } from '@/components/ui/otp-field';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { TextField } from '@/components/ui/text-field';
import { useTranslator } from '@/hooks/shared/use-translator';

interface Authenticator {
  authenticatorType?: string;
  name?: string;
}

interface OtpCodeFormProps {
  onSubmit: (code: string) => Promise<void>;
  onCancel: () => void;
  isLoading: boolean;
  authenticator?: Authenticator;
  onResend?: () => Promise<void>;
}

type CodeForm = { code: string };

/**
 * OTP / recovery-code input form for MFA step-up.
 *
 * Renders a 6-digit OTP field or a plain text field for recovery codes, with
 * Cancel and Verify buttons. Owns its own form state and auto-focuses on mount.
 *
 * @param props - Component props.
 * @param props.onSubmit - Called with the entered code on form submission.
 * @param props.onCancel - Called when the user cancels.
 * @param props.isLoading - Whether a verification request is in flight.
 * @returns Code input form element.
 * @internal
 */
export function OtpCodeForm({
  onSubmit,
  onCancel,
  isLoading,
  authenticator,
  onResend,
}: OtpCodeFormProps) {
  const { t } = useTranslator('gate_keeper');

  const [isResending, setIsResending] = useState(false);

  const isRecoveryCode = authenticator?.authenticatorType === FACTOR_TYPE_RECOVERY_CODE;

  const form = useForm<CodeForm>({ mode: 'onChange' });
  const code = form.watch('code');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  const handleResend = async () => {
    setIsResending(true);
    await onResend?.();
    form.reset();
    setIsResending(false);
  };

  const submitLabel = isLoading ? t('mfa.challenge.verifying') : t('mfa.verify_button');

  const description = authenticator?.name
    ? t('mfa.challenge.code_sent_description', { name: authenticator.name })
    : isRecoveryCode
      ? t('mfa.challenge.recovery_code_description')
      : t('mfa.challenge.otp_description');

  return (
    <Form {...form}>
      <form
        onSubmit={form.handleSubmit(({ code: enteredCode }) => onSubmit(enteredCode))}
        autoComplete="off"
        className="space-y-6"
      >
        <div className="space-y-4">
          {authenticator && (
            <p className="text-sm text-(length:--font-size-paragraph)">{description}</p>
          )}
          <FormField
            control={form.control}
            name="code"
            render={({ field }) => (
              <FormItem>
                <FormControl>
                  {isRecoveryCode ? (
                    <TextField
                      id="step-up-code"
                      {...field}
                      value={field.value || ''}
                      placeholder="XHPOWIHEFSDO23435pwe"
                      autoComplete="off"
                      ref={inputRef}
                    />
                  ) : (
                    <OTPField
                      id="step-up-code"
                      length={6}
                      separator={{ character: '-', afterEvery: 3 }}
                      onChange={field.onChange}
                      inputRef={inputRef}
                      value={field.value || ''}
                    />
                  )}
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
          {onResend && (
            <p className="text-sm text-muted-foreground text-center">
              {t('mfa.challenge.resend_prompt')}
              <Link onClick={handleResend} aria-disabled={isResending} className="text-sm ms-1">
                {t('mfa.challenge.resend')}
              </Link>
            </p>
          )}
        </div>

        <Separator />

        <div className="flex justify-end gap-3">
          <Button
            type="button"
            variant="outline"
            onClick={onCancel}
            disabled={isLoading}
            aria-label={t('mfa.back')}
          >
            {t('mfa.back')}
          </Button>
          <Button
            type="submit"
            variant="primary"
            disabled={(isRecoveryCode ? !code : code?.length !== 6) || isLoading}
            aria-label={submitLabel}
          >
            {isLoading && <Spinner size="sm" colorScheme="foreground" />}
            {submitLabel}
          </Button>
        </div>
      </form>
    </Form>
  );
}

/**
 * MFA step-up verify form.
 * @module step-up-verify-form
 * @internal
 */

import {
  FACTOR_TYPE_PUSH_NOTIFICATION,
  FACTOR_TYPE_RECOVERY_CODE,
  type MfaRequiredError,
} from '@auth0/universal-components-core';
import { useEffect, useState } from 'react';

import { OtpCodeForm } from './otp-code-form';

import { Button } from '@/components/ui/button';
import { DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Separator } from '@/components/ui/separator';
import { Spinner } from '@/components/ui/spinner';
import { useMfaStepUp } from '@/hooks/shared/use-mfa-step-up';
import { useTranslator } from '@/hooks/shared/use-translator';

interface VerifyAuthenticator {
  id?: string;
  authenticatorType: 'otp' | 'oob' | 'recovery-code';
  oobCode?: string;
  type?: string;
  name?: string;
}

interface VerifyFormProps {
  error: MfaRequiredError;
  authenticator: VerifyAuthenticator;
  onComplete: () => void;
  onCancel: () => void;
}

/**
 * Verify form for MFA step-up. Handles OTP, OOB (SMS, email, push, voice), and recovery-code authenticators.
 *
 * @param props - Component props.
 * @returns Verify form element.
 * @internal
 */
export function VerifyForm({ error, authenticator, onComplete, onCancel }: VerifyFormProps) {
  const { t } = useTranslator('gate_keeper');
  const { challenge, verify, isLoading } = useMfaStepUp({ error, onComplete });
  const mfaToken = error.mfa_token;

  const isOob = authenticator.authenticatorType === 'oob';
  const isRecoveryCode = authenticator.authenticatorType === FACTOR_TYPE_RECOVERY_CODE;
  const isPush = authenticator.type === FACTOR_TYPE_PUSH_NOTIFICATION;

  const [challenged, setChallenged] = useState(!isOob || !!authenticator.oobCode);
  const [oobCode, setOobCode] = useState<string | undefined>(authenticator.oobCode);

  const handleVerify = async (code: string) => {
    if (isOob) await verify({ mfaToken, oobCode, bindingCode: code });
    else if (isRecoveryCode) await verify({ mfaToken, recoveryCode: code });
    else await verify({ mfaToken, otp: code });
  };

  const handleResend = async () => {
    const response = await challenge(authenticator);
    if (response?.oobCode) setOobCode(response.oobCode);
  };

  useEffect(() => {
    if (!isOob || authenticator.oobCode) return;

    const initializeChallenge = async () => {
      const response = await challenge(authenticator);
      if (response?.oobCode) {
        setOobCode(response.oobCode);
        setChallenged(true);
      }
    };

    initializeChallenge();
  }, [isOob, challenge, authenticator.id, authenticator.oobCode]);

  if (!challenged) {
    return (
      <div className="flex items-center justify-center p-8" role="status" aria-live="polite">
        <Spinner />
      </div>
    );
  }

  if (isPush) {
    return (
      <>
        <DialogHeader>
          <DialogTitle>{t('mfa.challenge.push_title')}</DialogTitle>
          <DialogDescription>{t('mfa.challenge.push_description')}</DialogDescription>
        </DialogHeader>

        <p className="text-center text-sm text-(length:--font-size-paragraph) font-normal my-4">
          {t('mfa.challenge.push_waiting')}
        </p>

        <Separator />

        <div className="flex justify-end gap-3">
          <Button type="button" variant="outline" onClick={onCancel} aria-label={t('mfa.cancel')}>
            {t('mfa.cancel')}
          </Button>
          <Button
            type="button"
            variant="primary"
            onClick={onComplete}
            aria-label={t('mfa.continue')}
          >
            {t('mfa.continue')}
          </Button>
        </div>
      </>
    );
  }

  return (
    <>
      <DialogHeader>
        <DialogTitle>{t('mfa.title')}</DialogTitle>
      </DialogHeader>
      <Separator />
      <OtpCodeForm
        onSubmit={handleVerify}
        onCancel={onCancel}
        isLoading={isLoading}
        authenticator={authenticator}
        onResend={isOob && !isPush ? handleResend : undefined}
      />
    </>
  );
}

