 */

'use client';

import * as TooltipPrimitive from '@radix-ui/react-tooltip';
import { cva, type VariantProps } from 'class-variance-authority';
import * as React from 'react';

import { cn } from '@/lib/utils';
import { usePortalContainer } from '@/providers/portal-context';

const tooltipVariants = cva(
  'bg-popover text-popover-foreground data-[state=open]:animate-in data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95 data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 shadow-bevel-lg z-50 w-fit rounded-xl px-2 py-1 text-sm text-balance',
  {
    variants: {
      position: {
        top: 'origin-bottom',
        bottom: 'origin-top',
        left: 'origin-left',
        right: 'origin-right',
      },
    },
    defaultVariants: {
      position: 'top',
    },
  },
);

function Tooltip({ children, ...props }: React.ComponentProps<typeof TooltipPrimitive.Root>) {
  return (
    <TooltipPrimitive.Provider>
      <TooltipPrimitive.Root {...props}>{children}</TooltipPrimitive.Root>
    </TooltipPrimitive.Provider>
  );
}

function TooltipTrigger({
  asChild = true,
  ...props
}: React.ComponentProps<typeof TooltipPrimitive.Trigger>) {
  return <TooltipPrimitive.Trigger asChild={asChild} {...props} />;
}

interface TooltipContentProps
  extends React.ComponentProps<typeof TooltipPrimitive.Content>,
    VariantProps<typeof tooltipVariants> {}

const TooltipContent = React.forwardRef<
  React.ElementRef<typeof TooltipPrimitive.Content>,
  TooltipContentProps
>(({ className, side = 'top', position, sideOffset = 8, children, ...props }, ref) => {
  const portalContainer = usePortalContainer();
  return (
    <TooltipPrimitive.Portal container={portalContainer}>
      <TooltipPrimitive.Content
        ref={ref}
        side={side}
        sideOffset={sideOffset}
        className={cn(tooltipVariants({ position: position || side }), className)}
        {...props}
      >
        {children}
        <TooltipPrimitive.Arrow className="fill-popover" />
      </TooltipPrimitive.Content>
    </TooltipPrimitive.Portal>
  );
});
TooltipContent.displayName = TooltipPrimitive.Content.displayName;

export { Tooltip, TooltipTrigger, TooltipContent, tooltipVariants };

/**
 * Organization configuration hook.
 * @module use-config
 */

import {
  AVAILABLE_STRATEGY_LIST,
  hasApiErrorBody,
  type IdpStrategy,
} from '@auth0/universal-components-core';
import { useQuery, useQueryClient } from '@tanstack/react-query';

import { useCoreClient } from '@/hooks/shared/use-core-client';
import type { UseConfigResult } from '@/types/my-organization/config/config-types';

const configQueryKeys = {
  all: ['config'] as const,
  details: () => [...configQueryKeys.all, 'details'] as const,
};

/**
 * Hook for fetching organization configuration.
 * @returns Config data and allowed strategies.
 */
export function useConfig(): UseConfigResult {
  const { coreClient } = useCoreClient();
  const queryClient = useQueryClient();

  const configQuery = useQuery({
    queryKey: configQueryKeys.details(),
    queryFn: () => coreClient!.getMyOrganizationApiClient().organization.configuration.get(),
    enabled: !!coreClient,
    retry: (failureCount, error) => {
      if (hasApiErrorBody(error) && error.body?.status === 404) {
        return false;
      }
      return failureCount < 3;
    },
  });

  const config = configQuery.data;
  const allowedStrategies = config?.allowed_strategies;

  const filteredStrategies: IdpStrategy[] = allowedStrategies
    ? AVAILABLE_STRATEGY_LIST.filter((s) => allowedStrategies.includes(s))
    : AVAILABLE_STRATEGY_LIST;

  const shouldAllowDeletion =
    config?.connection_deletion_behavior === 'allow' ||
    config?.connection_deletion_behavior === 'allow_if_empty';

  const isConfigValid = !!allowedStrategies?.length;

  return {
    config: config ?? null,
    isLoadingConfig: configQuery.isLoading,
    fetchConfig: async () => await queryClient.getQueryData(configQueryKeys.details()),
    filteredStrategies,
    shouldAllowDeletion,
    isConfigValid,
  };
}

/**
 * Identity provider configuration hook.
 * @module use-idp-config
 */

import { hasApiErrorBody, type IdpStrategy } from '@auth0/universal-components-core';
import { useQuery, useQueryClient } from '@tanstack/react-query';

import { useCoreClient } from '@/hooks/shared/use-core-client';
import type {
  IdpConfig,
  UseConfigIdpResult,
} from '@/types/my-organization/config/config-idp-types';

export const idpConfigQueryKeys = {
  all: ['idp-config'] as const,
  config: () => [...idpConfigQueryKeys.all, 'config'] as const,
};

/**
 * Hook for fetching IDP configuration and provisioning settings.
 * @returns IDP config and provisioning utilities.
 */
export function useIdpConfig(): UseConfigIdpResult {
  const { coreClient } = useCoreClient();
  const queryClient = useQueryClient();

  const idpConfigQuery = useQuery({
    queryKey: idpConfigQueryKeys.config(),
    queryFn: async () => {
      try {
        const response = await coreClient!
          .getMyOrganizationApiClient()
          .organization.configuration.identityProviders.get();
        return response as unknown as IdpConfig;
      } catch (error) {
        if (hasApiErrorBody(error) && error.body?.status === 404) {
          return null;
        }
        throw error;
      }
    },
    enabled: !!coreClient,
    retry: (failureCount, error) => {
      if (hasApiErrorBody(error) && error.body?.status === 404) return false;
      return failureCount < 3;
    },
  });

  const idpConfig = idpConfigQuery.data ?? null;
  const strategies = idpConfig?.strategies;

  const isProvisioningEnabled = (strategy: IdpStrategy | undefined): boolean => {
    if (!strategy || !strategies?.[strategy]) return false;
    return strategies[strategy].enabled_features.includes('provisioning');
  };

  const isProvisioningMethodEnabled = (strategy: IdpStrategy | undefined): boolean => {
    if (!strategy || !strategies?.[strategy]) return false;
    return strategies[strategy].provisioning_methods.includes('scim');
  };

  return {
    idpConfig,
    isIdpConfigValid: !!strategies && Object.keys(strategies).length > 0,
    isLoadingIdpConfig: idpConfigQuery.isLoading,
    fetchIdpConfig: async () => await queryClient.getQueryData(idpConfigQueryKeys.config()),
    isProvisioningEnabled,
    isProvisioningMethodEnabled,
  };
}

/**
 * SSO provider table logic hook.
 * @module use-sso-provider-table-logic
 * @internal
 */

import type { IdentityProvider } from '@auth0/universal-components-core';
import { useCallback, useState } from 'react';

import { useConfig } from '@/hooks/my-organization/use-config';
import { useIdpConfig } from '@/hooks/my-organization/use-idp-config';
import type {
  UseSsoProviderTableLogicOptions,
  UseSsoProviderTableLogicResult,
} from '@/types/my-organization/idp-management/sso-provider/sso-provider-table-types';

/**
 * Logic hook for SSO provider table UI.
 * @param params - Hook options
 * @param params.readOnly - Whether the table is in read-only mode
 * @param params.isLoading - Loading state from parent/data hook
 * @param params.createAction - Action config for create
 * @param params.editAction - Action config for edit
 * @param params.deleteAction - Action config for delete
 * @param params.deleteFromOrganizationAction - Action config for remove from org
 * @param params.onEnableProvider - Handler for enabling/disabling provider
 * @param params.onDeleteConfirm - Handler for confirming delete
 * @param params.onRemoveConfirm - Handler for confirming remove from org
 * @returns Hook state and methods
 * @internal
 */
export function useSsoProviderTableLogic({
  readOnly,
  isLoading,
  createAction,
  editAction,
  deleteAction,
  deleteFromOrganizationAction,
  onEnableProvider,
  onDeleteConfirm,
  onRemoveConfirm,
}: UseSsoProviderTableLogicOptions): UseSsoProviderTableLogicResult {
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [showRemoveModal, setShowRemoveModal] = useState(false);
  const [selectedIdp, setSelectedIdp] = useState<IdentityProvider | null>(null);
  const { isLoadingConfig, shouldAllowDeletion, isConfigValid } = useConfig();
  const { isLoadingIdpConfig, isIdpConfigValid } = useIdpConfig();
  const shouldHideCreate = !isConfigValid || !isIdpConfigValid;
  const isViewLoading = isLoading || isLoadingConfig || isLoadingIdpConfig;

  const handleCreate = useCallback(() => {
    if (createAction?.onAfter) {
      createAction.onAfter();
    }
  }, [createAction]);

  const handleEdit = useCallback(
    (idp: IdentityProvider) => {
      if (editAction?.onAfter) {
        editAction.onAfter(idp);
      }
    },
    [editAction],
  );

  const handleDelete = useCallback(
    (idp: IdentityProvider) => {
      setSelectedIdp(idp);

      if (deleteAction?.onBefore) {
        const shouldProceed = deleteAction.onBefore(idp);
        if (!shouldProceed) return;
      }

      setShowDeleteModal(true);
    },
    [deleteAction],
  );

  const handleDeleteFromOrganization = useCallback(
    (idp: IdentityProvider) => {
      setSelectedIdp(idp);

      if (deleteFromOrganizationAction?.onBefore) {
        const shouldProceed = deleteFromOrganizationAction.onBefore(idp);
        if (!shouldProceed) return;
      }

      setShowRemoveModal(true);
    },
    [deleteFromOrganizationAction],
  );

  const handleToggleEnabled = useCallback(
    async (idp: IdentityProvider, enabled: boolean) => {
      if (readOnly || !onEnableProvider) return;
      await onEnableProvider(idp, enabled);
    },
    [readOnly, onEnableProvider],
  );

  const handleDeleteConfirm = useCallback(
    async (provider: IdentityProvider) => {
      await onDeleteConfirm(provider);
      setShowDeleteModal(false);
      setSelectedIdp(null);
    },
    [onDeleteConfirm],
  );

  const handleRemoveConfirm = useCallback(
    async (provider: IdentityProvider) => {
      await onRemoveConfirm(provider);
      setShowRemoveModal(false);
      setSelectedIdp(null);
    },
    [onRemoveConfirm],
  );

  return {
    isViewLoading,
    shouldAllowDeletion,
    showDeleteModal,
    shouldHideCreate,
    showRemoveModal,
    selectedIdp,
    setShowDeleteModal,
    setShowRemoveModal,
    setSelectedIdp,
    handleCreate,
    handleEdit,
    handleDelete,
    handleDeleteFromOrganization,
    handleToggleEnabled,
    handleDeleteConfirm,
    handleRemoveConfirm,
  };
}

/**
 * SSO provider table data and actions hook.
 * @module use-sso-provider-table
 */

import {
  OrganizationDetailsMappers,
  SsoProviderMappers,
  type UpdateIdentityProviderRequestContent,
  type ComponentAction,
  type IdentityProvider,
  type OrganizationPrivate,
  BusinessError,
} from '@auth0/universal-components-core';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useCallback, useEffect, useRef } from 'react';

import { showToast } from '@/components/auth0/shared/toast';
import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useErrorHandler } from '@/hooks/shared/use-error-handler';
import { useTranslator } from '@/hooks/shared/use-translator';
import type { UseSsoProviderTableReturn } from '@/types/my-organization/idp-management/sso-provider/sso-provider-table-types';

export const ssoProviderQueryKeys = {
  all: ['sso-providers'] as const,
  list: () => [...ssoProviderQueryKeys.all, 'list'] as const,
  organization: ['organization', 'details'] as const,
};

/**
 * Hook for SSO provider table data and CRUD operations.
 * @param deleteAction - Delete action handler.
 * @param removeFromOrg - Remove from org handler.
 * @param enableAction - Enable/disable handler.
 * @param customMessages - Translation overrides.
 * @returns Provider data, mutations, and actions.
 */
export function useSsoProviderTable(
  deleteAction?: ComponentAction<IdentityProvider, void>,
  removeFromOrg?: ComponentAction<IdentityProvider, void>,
  enableAction?: ComponentAction<IdentityProvider>,
  customMessages = {},
): UseSsoProviderTableReturn {
  const { t } = useTranslator('idp_management.notifications', customMessages);
  const { coreClient } = useCoreClient();
  const queryClient = useQueryClient();
  const handleError = useErrorHandler();
  const hasShownProvidersError = useRef(false);
  const hasShownOrganizationError = useRef(false);

  const providersQuery = useQuery({
    queryKey: ssoProviderQueryKeys.list(),
    queryFn: async () => {
      const response = await coreClient!
        .getMyOrganizationApiClient()
        .organization.identityProviders.list();
      return (response?.identity_providers ?? []) as IdentityProvider[];
    },
    enabled: !!coreClient,
  });

  const organizationQuery = useQuery({
    queryKey: ssoProviderQueryKeys.organization,
    queryFn: async () => {
      const response = await coreClient!.getMyOrganizationApiClient().organizationDetails.get();
      return OrganizationDetailsMappers.fromAPI(response);
    },
    enabled: !!coreClient,
  });

  useEffect(() => {
    if (providersQuery.isError && !hasShownProvidersError.current) {
      handleError(providersQuery.error, { fallbackMessage: t('general_error') });
      hasShownProvidersError.current = true;
    }

    if (!providersQuery.isError) {
      hasShownProvidersError.current = false;
    }
  }, [providersQuery.isError, providersQuery.error, t, handleError]);

  useEffect(() => {
    if (organizationQuery.isError && !hasShownOrganizationError.current) {
      handleError(organizationQuery.error, { fallbackMessage: t('general_error') });
      hasShownOrganizationError.current = true;
    }

    if (!organizationQuery.isError) {
      hasShownOrganizationError.current = false;
    }
  }, [organizationQuery.isError, organizationQuery.error, t, handleError]);

  const enableProviderMutation = useMutation({
    mutationFn: async ({
      selectedIdp,
      enabled,
    }: {
      selectedIdp: IdentityProvider;
      enabled: boolean;
    }): Promise<IdentityProvider> => {
      if (!selectedIdp?.id) {
        throw new Error('Invalid provider');
      }

      if (enableAction?.onBefore) {
        const shouldProceed = enableAction.onBefore(selectedIdp);
        if (!shouldProceed) {
          throw new BusinessError({ message: t('general_error') });
        }
      }

      const apiRequestData: UpdateIdentityProviderRequestContent = SsoProviderMappers.updateToAPI({
        strategy: selectedIdp.strategy,
        is_enabled: enabled,
      });

      const updatedProvider = await coreClient!
        .getMyOrganizationApiClient()
        .organization.identityProviders.update(selectedIdp.id, apiRequestData);

      return updatedProvider as IdentityProvider;
    },
    onSuccess: async (updatedProvider, { selectedIdp }) => {
      if (enableAction?.onAfter) {
        await enableAction.onAfter(selectedIdp);
      }

      showToast({
        type: 'success',
        message: t('update_success', { providerName: selectedIdp.display_name }),
      });

      // Update the cache optimistically
      queryClient.setQueryData<IdentityProvider[]>(ssoProviderQueryKeys.list(), (old) => {
        if (!old) return old;
        return old.map((provider) =>
          provider.id === selectedIdp.id ? { ...provider, ...updatedProvider } : provider,
        );
      });
    },
    onError: (error) => {
      handleError(error, { fallbackMessage: t('general_error') });
    },
  });

  const deleteProviderMutation = useMutation({
    mutationFn: async (selectedIdp: IdentityProvider): Promise<void> => {
      if (!selectedIdp?.id) {
        throw new Error('Invalid provider');
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .organization.identityProviders.delete(selectedIdp.id);
    },
    onSuccess: async (_, selectedIdp) => {
      if (deleteAction?.onAfter) {
        await deleteAction.onAfter(selectedIdp);
      }

      showToast({
        type: 'success',
        message: t('delete_success', { providerName: selectedIdp.display_name }),
      });

      queryClient.invalidateQueries({ queryKey: ssoProviderQueryKeys.list() });
    },
    onError: (error) => {
      handleError(error, { fallbackMessage: t('general_error') });
    },
  });

  const removeProviderMutation = useMutation({
    mutationFn: async (selectedIdp: IdentityProvider): Promise<void> => {
      if (!selectedIdp?.id) {
        throw new Error('Invalid provider');
      }

      await coreClient!
        .getMyOrganizationApiClient()
        .organization.identityProviders.detach(selectedIdp.id);
    },
    onSuccess: async (_, selectedIdp) => {
      if (removeFromOrg?.onAfter) {
        await removeFromOrg.onAfter(selectedIdp);
      }

      const organizationData = queryClient.getQueryData<OrganizationPrivate>(
        ssoProviderQueryKeys.organization,
      );

      showToast({
        type: 'success',
        message: t('remove_success', {
          providerName: selectedIdp.display_name,
          organizationName: organizationData?.display_name,
        }),
      });

      queryClient.invalidateQueries({ queryKey: ssoProviderQueryKeys.list() });
    },
    onError: (error) => {
      handleError(error, { fallbackMessage: t('general_error') });
    },
  });

  const onEnableProvider = useCallback(
    async (selectedIdp: IdentityProvider, enabled: boolean): Promise<boolean> => {
      if (!selectedIdp || !coreClient || !selectedIdp.id) {
        return false;
      }

      try {
        await enableProviderMutation.mutateAsync({ selectedIdp, enabled });
        return true;
      } catch {
        return false;
      }
    },
    [coreClient, enableProviderMutation],
  );

  const onDeleteConfirm = useCallback(
    async (selectedIdp: IdentityProvider): Promise<void> => {
      if (!selectedIdp || !coreClient || !selectedIdp.id) {
        return;
      }

      deleteProviderMutation.mutate(selectedIdp);
    },
    [coreClient, deleteProviderMutation],
  );

  const onRemoveConfirm = useCallback(
    async (selectedIdp: IdentityProvider): Promise<void> => {
      if (!selectedIdp || !coreClient || !selectedIdp.id) {
        return;
      }

      removeProviderMutation.mutate(selectedIdp);
    },
    [coreClient, removeProviderMutation],
  );

  const fetchProviders = useCallback(async (): Promise<void> => {
    await queryClient.getQueryData(ssoProviderQueryKeys.list());
  }, [queryClient]);

  const fetchOrganizationDetails = useCallback(async (): Promise<OrganizationPrivate | null> => {
    if (!coreClient) {
      return null;
    }

    try {
      const data = await queryClient.ensureQueryData({
        queryKey: ssoProviderQueryKeys.organization,
        queryFn: async () => {
          const response = await coreClient.getMyOrganizationApiClient().organizationDetails.get();
          return OrganizationDetailsMappers.fromAPI(response);
        },
      });
      return data;
    } catch (error) {
      handleError(error, { fallbackMessage: t('general_error') });
      return null;
    }
  }, [coreClient, queryClient, t, handleError]);

  return {
    // Data from TanStack Query - single source of truth
    providers: providersQuery.data ?? [],
    organization: organizationQuery.data ?? null,

    // Loading states - all derived from TanStack Query
    isLoading: providersQuery.isLoading || organizationQuery.isLoading,
    isDeleting: deleteProviderMutation.isPending,
    isRemoving: removeProviderMutation.isPending,
    isUpdating: enableProviderMutation.isPending,
    isUpdatingId: enableProviderMutation.isPending
      ? (enableProviderMutation.variables?.selectedIdp?.id ?? null)
      : null,

    // Actions
    fetchProviders,
    fetchOrganizationDetails,
    onDeleteConfirm,
    onRemoveConfirm,
    onEnableProvider,
  };
}

/**
 * CoreClient initialization hook.
 * @module use-core-client-initialization
 * @internal
 */

import type {
  CoreClientInterface,
  AuthDetails,
  I18nInitOptions,
} from '@auth0/universal-components-core';
import { createCoreClient } from '@auth0/universal-components-core';
import * as React from 'react';

interface UseCoreClientInitializationProps {
  authDetails: AuthDetails;
  i18nOptions?: I18nInitOptions;
}

/**
 * @internal
 * @param props - Initialization props.
 * @returns The initialized CoreClient instance, or null while initializing.
 */
export const useCoreClientInitialization = ({
  authDetails,
  i18nOptions,
}: UseCoreClientInitializationProps): CoreClientInterface | null => {
  const { authProxyUrl } = authDetails;
  const [coreClient, setCoreClient] = React.useState<CoreClientInterface | null>(null);

  React.useEffect(() => {
    const initializeCoreClient = async () => {
      try {
        const initializedCoreClient = await createCoreClient(authDetails, i18nOptions);
        setCoreClient(initializedCoreClient);
      } catch (error) {
        console.error(error);
      }
    };
    initializeCoreClient();
  }, [authProxyUrl, i18nOptions]);

  return coreClient;
};

/**
 * CoreClient context and hook.
 * @module use-core-client
 */

import type { CoreClientInterface } from '@auth0/universal-components-core';
import * as React from 'react';

/** @internal */
const CoreClientContext = React.createContext<{
  coreClient: CoreClientInterface | null;
}>({
  coreClient: null,
});

/**
 * Hook to access CoreClient from context.
 * @returns CoreClient instance or null.
 * @throws If used outside Auth0ComponentProvider.
 */
export const useCoreClient = () => {
  const context = React.useContext(CoreClientContext);
  if (!context) {
    throw new Error('useCoreClient must be used within Auth0ComponentProvider');
  }
  return context;
};

export { CoreClientContext };

/**
 * Error handling hook with toast error.
 * @module use-error-handler
 */

import {
  isNotifiableError,
  resolveErrorMessage,
  getStatusCode,
  hasApiErrorBody,
  ERROR_CODES,
} from '@auth0/universal-components-core';
import { useCallback } from 'react';

import { showToast } from '@/components/auth0/shared/toast';
import { useTranslator } from '@/hooks/shared/use-translator';

interface ErrorHandlerCallOptions {
  fallbackMessage?: string;
}

/**
 * Hook for consistent error handling across the app.
 *
 * @returns Error handler function.
 *
 * @example
 * const handleError = useErrorHandler();
 *
 * // With custom message
 * onError: (error) => handleError(error, {
 *   fallbackMessage: t('my_error')
 * });
 *
 * // With defaults
 * onError: handleError;
 */
export function useErrorHandler() {
  const { t } = useTranslator('common');

  return useCallback(
    (error: unknown, options: ErrorHandlerCallOptions = {}): void => {
      if (!isNotifiableError(error)) return;

      const getCustomErrorMessage = (err: unknown): string | undefined => {
        const status = getStatusCode(err);
        switch (status) {
          case 400:
            return t('error.bad_request');
          case 401:
            return t('error.missing_token');
          case 403:
            return hasApiErrorBody(err) && err.body?.type?.includes(ERROR_CODES.INSUFFICIENT_SCOPE)
              ? t('error.insufficient_scope')
              : t('error.forbidden');
          case 404:
            return t('error.not_found');
          case 429:
            return t('error.rate_limit');
          default:
            return undefined;
        }
      };

      showToast({
        type: 'error',
        message:
          getCustomErrorMessage(error) ??
          resolveErrorMessage(error, options.fallbackMessage ?? t('error.generic')),
      });
    },
    [t],
  );
}

import { FACTOR_TYPE_RECOVERY_CODE, type MfaRequiredError } from '@auth0/universal-components-core';
import { useQuery } from '@tanstack/react-query';
import { useEffect, useMemo } from 'react';

import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useErrorHandler } from '@/hooks/shared/use-error-handler';

/**
 * Resolves MFA enrollment factors and active authenticators for a step-up flow.
 *
 * Fetches enrollment factors (normal mode) or authenticators (proxy mode), falling back to
 * `error.mfa_requirements.enroll` when in proxy mode with no active authenticators.
 *
 * @param error - The MFA required error containing the `mfa_token` and optional requirements.
 * @returns Resolved `factors`, `authenticators`, `isEnrollMode`, and `isLoading`.
 * @internal
 */
export function useMfaRequirements(error: MfaRequiredError) {
  const { coreClient } = useCoreClient();
  const handleError = useErrorHandler();
  const mfaToken = error.mfa_token;

  const stepUpClient = coreClient?.getMFAStepUpApiClient();
  const isProxyMode = !!coreClient?.isProxyMode();

  const enrollment = useQuery({
    queryKey: ['mfa-enrollment-factors', mfaToken],
    queryFn: () => stepUpClient!.getEnrollmentFactors!(mfaToken),
    enabled: !!stepUpClient && !!stepUpClient.getEnrollmentFactors && !isProxyMode,
    select: (factors) => factors.filter((f) => f.type !== FACTOR_TYPE_RECOVERY_CODE),
    retry: false,
  });

  const authenticators = useQuery({
    queryKey: ['mfa-authenticators', mfaToken],
    queryFn: () => stepUpClient!.getAuthenticators(mfaToken),
    enabled: !!stepUpClient && (isProxyMode || (enrollment.isSuccess && !enrollment.data.length)),
    select: (items) => items.filter((a) => a.active),
    retry: false,
  });

  useEffect(() => {
    if (enrollment.isError) handleError(enrollment.error);
  }, [enrollment.isError, enrollment.error, handleError]);

  useEffect(() => {
    if (authenticators.isError) handleError(authenticators.error);
  }, [authenticators.isError, authenticators.error, handleError]);

  const factors = useMemo(() => {
    if (isProxyMode) {
      if (authenticators.isSuccess && authenticators.data.length === 0) {
        return (error.mfa_requirements?.enroll ?? []).filter(
          (f) => f.type !== FACTOR_TYPE_RECOVERY_CODE,
        );
      }
      return [];
    }
    return enrollment.data ?? [];
  }, [enrollment.data, authenticators.isSuccess, authenticators.data, isProxyMode, error]);

  return {
    factors,
    authenticators: authenticators.data ?? [],
    isEnrollMode: factors.length > 0,
    isLoading: enrollment.isLoading || authenticators.isLoading,
  };
}

/**
 * MFA step-up operations hook.
 * @module use-mfa-step-up
 * @internal
 */

import {
  type EnrollParams,
  type MfaRequiredError,
  type VerifyParams,
} from '@auth0/universal-components-core';
import { useCallback, useState } from 'react';

import { useCoreClient } from '@/hooks/shared/use-core-client';
import { useErrorHandler } from '@/hooks/shared/use-error-handler';

interface UseMfaStepUpProps {
  error: MfaRequiredError;
  onComplete: () => void;
}

/**
 * Wraps MFA step-up API operations with error handling and shared loading state.
 *
 * @param props - Hook configuration.
 * @param props.error - The MFA required error containing the `mfa_token`.
 * @param props.onComplete - Called after a successful `verify`.
 * @returns `enroll`, `challenge`, `verify`, and `isLoading`.
 * @internal
 */
export function useMfaStepUp({ error, onComplete }: UseMfaStepUpProps) {
  const { coreClient } = useCoreClient();
  const handleError = useErrorHandler();
  const stepUpClient = coreClient!.getMFAStepUpApiClient();

  const mfaToken = error.mfa_token;
  const [isLoading, setIsLoading] = useState(false);

  const enroll = useCallback(
    async (params: EnrollParams) => {
      setIsLoading(true);
      try {
        return await stepUpClient.enroll(params);
      } catch (err) {
        handleError(err);
        return undefined;
      } finally {
        setIsLoading(false);
      }
    },
    [stepUpClient, handleError],
  );

  const challenge = useCallback(
    async (authenticator: { id?: string }) => {
      try {
        return await stepUpClient.challenge({
          mfaToken,
          challengeType: 'oob',
          authenticatorId: authenticator.id,
        });
      } catch (err) {
        handleError(err);
        return undefined;
      }
    },
    [mfaToken, stepUpClient, handleError],
  );

  const verify = useCallback(
    async (params: VerifyParams) => {
      setIsLoading(true);
      try {
        await stepUpClient.verify(params);
        onComplete();
      } catch (err) {
        handleError(err);
      } finally {
        setIsLoading(false);
      }
    },
    [stepUpClient, handleError, onComplete],
  );

  return { enroll, challenge, verify, isLoading };
}

