/**
 * Toast notification types.
 * @module toast-types
 */

import type { ReactNode } from 'react';
import type { ExternalToast } from 'sonner';

/** Toast notification type. */
export type ToastType = 'success' | 'info' | 'warning' | 'error';

/** Toast position options. */
export type ToastPosition =
  | 'top-left'
  | 'top-right'
  | 'bottom-left'
  | 'bottom-right'
  | 'top-center'
  | 'bottom-center';

/** Custom toast method signature. */
export interface CustomToastMethod {
  (message: string): void;
}

/** Custom toast methods for overriding default behavior. */
export interface CustomToastMethods {
  success?: CustomToastMethod;
  error?: CustomToastMethod;
  warning?: CustomToastMethod;
  info?: CustomToastMethod;
  dismiss?: (toastId?: string) => void;
}

/** Sonner toast settings. */
export interface SonnerSettings {
  position?: ToastPosition;
  maxToasts?: number;
  duration?: number;
  dismissible?: boolean;
  closeButton?: boolean;
}

/** Toast provider configuration. */
export type ToastSettings =
  | { provider?: 'sonner'; settings?: SonnerSettings }
  | { provider: 'custom'; methods: CustomToastMethods };

/** Toast options for showToast. */
export interface ToastOptions {
  type: ToastType;
  message: string;
  className?: string;
  icon?: ReactNode;
  data?: ExternalToast;
}

/** Default toast settings. */
export const DEFAULT_TOAST_SETTINGS: ToastSettings = {
  provider: 'sonner',
  settings: {
    position: 'top-right',
    closeButton: true,
  },
} as const;

/**
 * Tailwind CSS utility functions.
 * @module utils
 * @internal
 */

import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

/**
 * Merges class names with Tailwind CSS conflict resolution.
 * @param inputs - Input values to process
 * @returns The merged class name string
 * @internal
 */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

/**
 * Apple logo icon component.
 * @module apple-logo
 * @internal
 */

import { AppleLogoSvg } from '@auth0/universal-components-core';
import React from 'react';

export interface AppleLogoProps extends React.ImgHTMLAttributes<HTMLImageElement> {
  width?: number | string;
  height?: number | string;
  title?: string;
}

/**
 * AppleLogo component renders the Apple SVG logo.
 *
 * @param props - Props including width, height, title, and standard SVG attributes.
 * @returns A JSX element with the Apple logo image.
 */
const AppleLogo: React.FC<AppleLogoProps> = ({
  width = 30,
  height = 30,
  title = 'Apple logo',
  className,
  ...props
}) => {
  return (
    <img
      src={AppleLogoSvg}
      alt={title}
      width={width}
      height={height}
      className={className}
      {...props}
    />
  );
};

export default React.memo(AppleLogo);

